+#[cfg(unix)]
+extern "C" {
+    fn kill(pid: i32, sig: i32) -> i32;
+    fn __errno_location() -> *mut i32;
+}
+
+#[cfg(unix)]
+unsafe fn libc_kill(pid: i32, sig: i32) -> i32 {
+    unsafe { kill(pid, sig) }
+}
+
+#[cfg(unix)]
+unsafe fn errno_location() -> *mut i32 {
+    unsafe { __errno_location() }
+}
